#include <unordered_map>
#include <string>
#include <vector>

class Solution {
public:
    std::string countOfAtoms(std::string formula) {
        std::unordered_map<char, int> countMap;
        std::vector<std::string> atoms;

        for (char c : formula) {
            if (isalpha(c)) {
                atoms.push_back(c);
            } else {
                int count = stoi(std::string(1, c));
                countMap[c] += count;
            }
        }

        std::string result;
        for (const auto& atom : atoms) {
            result += atom + " " + to_string(countMap[atom] + 1);
        }

        return result;
    }
};
